public class SimpleLinearRegression {
 private double slope;
 private double intercept;

 public void fit(double[] x, double[] y) {
 int n = x.length;
 double sumX = 0, sumY = 0, sumXY = 0, sumX2 = 0;

 for (int i = 0; i < n; i++) {
 sumX += x[i];
 sumY += y[i];
 sumXY += x[i] * y[i];
 sumX2 += x[i] * x[i];
 }

 // Normal equation solution
 double denominator = n * sumX2 - sumX * sumX;
 slope = (n * sumXY - sumX * sumY) / denominator;
 intercept = (sumY - slope * sumX) / n;
 }

 public double predict(double x) {
 return slope * x + intercept;
 }

 public double mse(double[] x, double[] y) {
 double sum = 0;
 for (int i = 0; i < x.length; i++) {
 double error = y[i] - predict(x[i]);
 sum += error * error;
 }
 return sum / x.length;
 }

 public static void main(String[] args) {
 double[] x = {1, 2, 3, 4, 5};
 double[] y = {2.2, 4.1, 5.9, 8.0, 9.8};

 SimpleLinearRegression model = new SimpleLinearRegression();
 model.fit(x, y);

 System.out.printf("y = %.2fx + %.2f%n", model.slope, model.intercept);
 System.out.printf("Prediction for x=6: %.2f%n", model.predict(6));
 System.out.printf("MSE: %.4f%n", model.mse(x, y));
 }
}
